     */
    fun getBenchmarkProblemSize(benchmark: String, default: Int): Int {
        val normalizedName = benchmark.uppercase()
        val problemSize = benchmarks[normalizedName] ?: -1
        return if (problemSize == -1) default else problemSize
    }

    companion object {
